// ============= 真人发音播放器 =============
// AUDIO 对象：key 是法语词/句（精确匹配或归一化匹配），value 是 base64 mp3 data URL
// 拿到 mp3 后只需要往这里填条目即可，不需要改其他逻辑
const AUDIO = {
  // 示例（待替换为真实 base64）：
  // 'Écoute': 'data:audio/mp3;base64,...',
  // 'un crayon': 'data:audio/mp3;base64,...',
};

// 归一化 key，提高匹配率（去标点、去多余空格、统一大小写）
const normAudioKey = (s) => {
  if (!s) return '';
  return s.trim()
    .replace(/[.!?,;:]+$/, '')   // 去除末尾标点
    .replace(/\s+/g, ' ')        // 多空格合一
    .toLowerCase();
};

// 缓存归一化后的 AUDIO 索引
let _audioIndex = null;
const buildAudioIndex = () => {
  if (_audioIndex) return _audioIndex;
  _audioIndex = {};
  Object.keys(AUDIO).forEach(k => {
    _audioIndex[normAudioKey(k)] = AUDIO[k];
  });
  return _audioIndex;
};

// 查找：精确 → 归一化匹配
const findAudio = (text) => {
  if (!text) return null;
  const idx = buildAudioIndex();
  return idx[normAudioKey(text)] || null;
};

// 播放真人 mp3，返回 Promise（成功 resolve，失败 reject）
const playRealAudio = (text) => new Promise((resolve, reject) => {
  const url = findAudio(text);
  if (!url) return reject(new Error('no audio'));
  try {
    const audio = new Audio(url);
    audio.volume = 0.95;
    audio.onended = () => resolve();
    audio.onerror = () => reject(new Error('play failed'));
    audio.play().catch(reject);
  } catch (e) { reject(e); }
});

// ============= 语音朗读 (TTS) =============
let TTS_ON = false;  // 默认关闭：合成语音感觉诡异，需要时手动开启
let TTS_UNLOCKED = false;  // 浏览器是否已解锁语音权限
let _voicesCache = [];

const _loadVoices = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;
  const v = window.speechSynthesis.getVoices();
  if (v.length) _voicesCache = v;
};

if (typeof window !== 'undefined' && window.speechSynthesis) {
  _loadVoices();
  window.speechSynthesis.onvoiceschanged = _loadVoices;
}

// 关键：在用户首次点击时解锁 TTS（播放一个空白 utterance 来激活权限）
const unlockTTS = () => {
  if (TTS_UNLOCKED) return;
  if (typeof window === 'undefined' || !window.speechSynthesis) return;
  try {
    const u = new SpeechSynthesisUtterance('');
    u.volume = 0;
    window.speechSynthesis.speak(u);
    TTS_UNLOCKED = true;
    // 再拉一次 voices，某些浏览器此时才返回
    setTimeout(_loadVoices, 100);
  } catch (e) { /* ignore */ }
};

// 挑选最合适的语音（优先女声/儿童声，匹配角色 Emilie 是法国小女孩）
const pickVoice = (lang, prefer = 'female') => {
  if (!_voicesCache.length) _loadVoices();
  if (!_voicesCache.length) return null;

  // 过滤出语言匹配的所有 voice
  const langPrefix = lang.split('-')[0].toLowerCase();
  const langMatches = _voicesCache.filter(v =>
    v.lang && (v.lang === lang || v.lang.toLowerCase().startsWith(langPrefix))
  );
  if (!langMatches.length) return null;

  // 女声/儿童声关键词（不同系统用词不同）
  const FEMALE_KEYWORDS = [
    'female', 'woman', 'girl', 'enfant', 'child',
    // macOS / iOS 法语女声
    'amelie', 'amélie', 'audrey', 'virginie', 'aurelie', 'aurélie', 'marie',
    // Windows 法语女声
    'hortense', 'julie', 'caroline',
    // Google 法语女声
    'celine', 'céline',
    // 通用
    'siri', 'samantha',
  ];
  const MALE_KEYWORDS = ['male', 'man', 'thomas', 'paul', 'nicolas', 'henri', 'daniel', 'fred'];

  const isFemale = (v) => {
    const n = (v.name || '').toLowerCase();
    if (FEMALE_KEYWORDS.some(k => n.includes(k))) return true;
    if (MALE_KEYWORDS.some(k => n.includes(k))) return false;
    return null; // 不确定
  };

  if (prefer === 'female') {
    // 1. 明确女声 + 精确语言
    let m = langMatches.find(v => v.lang === lang && isFemale(v) === true);
    if (m) return m;
    // 2. 明确女声 + 语言前缀
    m = langMatches.find(v => isFemale(v) === true);
    if (m) return m;
    // 3. 不是明确男声 + 精确语言
    m = langMatches.find(v => v.lang === lang && isFemale(v) !== false);
    if (m) return m;
    // 4. 不是明确男声
    m = langMatches.find(v => isFemale(v) !== false);
    if (m) return m;
  }
  // 兜底：精确匹配 → 前缀匹配 → 第一个
  return langMatches.find(v => v.lang === lang) || langMatches[0];
};

// 朗读 - 必须在用户点击回调中同步调用！
const speak = (text, lang = 'fr-FR', opts = {}) => {
  if (!TTS_ON) return;
  if (typeof window === 'undefined' || !window.speechSynthesis) return;
  if (!text || !text.trim()) return;
  try {
    window.speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.lang = lang;
    const voice = pickVoice(lang, 'female');
    if (voice) u.voice = voice;
    u.rate = opts.rate != null ? opts.rate : (lang.startsWith('fr') ? 0.82 : (opts.shanghai ? 0.9 : 0.95));
    // 法语默认音调上调到 1.25，更接近少女声（Emilie 是小女孩）
    u.pitch = opts.pitch != null ? opts.pitch : (lang.startsWith('fr') ? 1.25 : 1.1);
    u.volume = opts.volume != null ? opts.volume : 0.95;
    window.speechSynthesis.speak(u);
  } catch (e) { /* 静默失败 */ }
};

// 上海话朗读策略（A 方案）：
// 主要靠普通话 TTS + 沪语韵律调整（rate 0.85、pitch 0.92，柔软拖腔感）
// 少数最有沪语辨识度的"招牌词"用拟音，保留沪语味道
const SHANGHAINESE_SIGNATURE = {
  '侬': 'nóng',        // "你"，沪语最经典一字
  '小囡': 'xiǎo nuō',  // "小孩"
  '交关': 'gāo guē',   // "非常"
  '辰光': 'sén guāng', // "时候"
  '吃啥': 'qì sá',     // "吃什么"
  '阿拉': 'ā lā',      // "我们"
  '伊': 'yí',          // "他/她"
};

// 转换：只替换招牌词，其他字保留原样让普通话 TTS 正常读
const toShanghaineseReading = (text) => {
  let out = text;
  const keys = Object.keys(SHANGHAINESE_SIGNATURE).sort((a, b) => b.length - a.length);
  keys.forEach(k => {
    out = out.split(k).join(' ' + SHANGHAINESE_SIGNATURE[k] + ' ');
  });
  // 清理多余空格
  return out.replace(/\s+/g, ' ').trim();
};

// 角色是否说沪语（上海本地NPC）
const SHANGHAINESE_SPEAKERS = new Set(['爷爷', '老板', '妈妈', '爸爸']);

// 从 speech 文本中提取法语或中文部分朗读
const speakSmartSpeech = (text, who) => {
  if (!text) return;
  const trimmed = text.trim();
  // 纯法语检测
  const frenchRegex = /^[a-zA-ZÀ-ÿ\s,.!?'"：;:\-…—()0-9]+$/;
  const firstSentence = trimmed.split(/[。！？…]/)[0].trim();
  if (frenchRegex.test(firstSentence)) {
    // 优先真人发音
    playRealAudio(firstSentence).catch(() => speak(firstSentence, 'fr-FR'));
    return;
  }
  // 混合文本：先找法语片段
  const frMatch = trimmed.match(/[a-zA-ZÀ-ÿ][a-zA-ZÀ-ÿ\s',.!?\-]+[a-zA-ZÀ-ÿ]/);
  if (frMatch && frMatch[0].length >= 4) {
    const fr = frMatch[0].trim();
    playRealAudio(fr).catch(() => speak(fr, 'fr-FR'));
    return;
  }
  // 纯中文分支
  if (/[\u4e00-\u9fa5]/.test(trimmed)) {
    if (who && SHANGHAINESE_SPEAKERS.has(who)) {
      const reading = toShanghaineseReading(trimmed);
      speak(reading, 'zh-CN', { rate: 0.85, pitch: 0.92, volume: 0.95 });
    } else {
      speak(trimmed, 'zh-CN', { rate: 0.95, pitch: 1.05 });
    }
  }
};

